section.para:
The CacheDB URL that associates this module with a named cache group
in the &osips; script.  The URL format follows the standard &osips;
CacheDB convention:

listitem.para:
subject (string) —
NATS subject to send the request to.  May contain &osips;
pseudo-variables.

example.programlisting:
...
$var(req) = "{\"user\":\"" + $fU + "\",\"domain\":\"" + $fd + "\"}";
nats_request("auth.check", $var(req), 2000, $var(reply));
if ($retcode == 1) {
    xlog("auth service replied: $var(reply)\n");
} else if ($retcode == -2) {
    xlog("auth service timed out\n");
    sl_send_reply(503, "Service Unavailable");
    exit;
}
...

...
cache_fetch("nats", "call.$ci", $var(call_info));
if ($retcode == -2) {
    xlog("no active call record for $ci\n");
}
...

...
cache_add("nats", "counter.calls.$fU", 1, 0);
cache_counter_fetch("nats", "counter.calls.$fU", $var(call_count));
xlog("$fU has $var(call_count) active calls\n");
...

...
cache_counter_fetch("nats", "counter.calls.$fU", $var(n));
if ($var(n) > 5) {
    sl_send_reply(503, "Too Many Calls");
    exit;
}
...

...
# Find all documents where the "domain" field equals "example.com"
cache_query("nats", "domain", "example.com", $var(results));
if ($retcode == 1) {
    xlog("matched documents: $var(results)\n");
}
...

...
startup_route {
    subscribe_event("E_NATS_KV_CHANGE", "nats:opensips-events");
}

event_route[E_NATS_KV_CHANGE] {
    xlog("KV change: key=$param(key) op=$param(operation) rev=$param(revision)\n");
    if ($param(operation) == "put") {
        xlog("  new value: $param(value)\n");
    }
}
...
